using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // EF Core 9 changed the default discriminator property from "Discriminator" to "$type".
            // Existing 500K documents and direct SQL queries reference c.Discriminator,
            // so we must preserve the old name.
            entity.HasDiscriminator<string>("Discriminator");

            // EF Core 9 changed id values from "EntityType|Key" (e.g. "Product|123") to just
            // the key value ("123"). Existing documents use the old compound format, so we must
            // preserve it to keep FindAsync and point-reads working.
            entity.HasRootDiscriminatorInJsonId(true);
        });

        // HasIndex was removed — EF Core 9 Cosmos provider now throws at startup.
        // Manage indexing policy via the Azure Portal, Bicep, or Terraform instead.
    }
}
class Product { public int Id { get; set; } public string Sku { get; set; } }

